import React from 'react';
import type {
  CommonProps,
  MarginProps,
  PropsWithHTMLElement,
  ExpandProps,
} from '@contentful/f36-core';
import { Text } from '@contentful/f36-typography';
import { useFormControl } from '../FormControl/FormControlContext';
import { useDensity } from '@contentful/f36-utils';

export interface HelpTextInternalProps extends CommonProps, MarginProps {
  children: React.ReactNode;
}

export type HelpTextProps = PropsWithHTMLElement<HelpTextInternalProps, 'p'>;

/**
 * `HelpText` is a styled copy block with guidance, placed in the context of form components.
 */

export const HelpText = React.forwardRef<
  HTMLParagraphElement,
  ExpandProps<HelpTextProps>
>(({ testId = 'cf-ui-help-text', ...otherProps }, ref) => {
  const { id } = useFormControl({});
  const density = useDensity();
  return (
    <Text
      as="p"
      fontColor="gray500"
      fontSize={density === 'high' ? 'fontSizeMHigh' : 'fontSizeM'}
      lineHeight={density === 'high' ? 'lineHeightMHigh' : 'lineHeightM'}
      testId={testId}
      id={`${id}-helptext`}
      marginTop="spacingXs"
      {...otherProps}
      ref={ref}
    />
  );
});

HelpText.displayName = 'HelpText';
import { createContext, useContext } from 'react';
import type { FormControlContextProps } from './types';

const noop = () => {
  // do nothing
};

export const FormControlContext = createContext<
  FormControlContextProps | undefined
>(undefined);

export const useFormControlContext = () => {
  const context = useContext(FormControlContext);
  return context;
};

export const useFormControl = (
  props: Partial<FormControlContextProps>,
): FormControlContextProps => {
  const context = useFormControlContext();
  if (!context) {
    return props;
  }
  return {
    isDisabled: props.isDisabled ?? context.isDisabled,
    isInvalid: props.isInvalid ?? context.isInvalid,
    isReadOnly: props.isReadOnly ?? context.isReadOnly,
    isRequired: props.isRequired ?? context.isRequired,
    id: props.id ?? context.id,
    maxLength: context.maxLength,
    inputValue: context.inputValue,
    setMaxLength: context.setMaxLength || noop,
    setInputValue: context.setInputValue || noop,
  };
};
import React, { forwardRef } from 'react';
import {
  Flex,
  type CommonProps,
  type MarginProps,
  type PropsWithHTMLElement,
  type ExpandProps,
} from '@contentful/f36-core';
import { ErrorCircleOutlineIcon } from '@contentful/f36-icons';
import { Text } from '@contentful/f36-typography';
import { useFormControl } from '../FormControl/FormControlContext';
import { useDensity } from '@contentful/f36-utils';

export interface ValidationMessageInternalProps
  extends CommonProps,
    MarginProps {
  children: React.ReactNode;
}

export type ValidationMessageProps = PropsWithHTMLElement<
  ValidationMessageInternalProps,
  'div'
>;

export const ValidationMessage = forwardRef<
  HTMLDivElement,
  ExpandProps<ValidationMessageProps>
>(({ children, testId = 'cf-ui-validation-message', ...otherProps }, ref) => {
  const { id } = useFormControl({});
  const density = useDensity();

  return (
    <Flex
      marginTop="spacing2Xs"
      {...otherProps}
      ref={ref}
      testId={testId}
      alignItems="center"
      id={id ? `${id}-validation` : undefined}
      aria-live="assertive"
    >
      <Flex marginRight={density === 'high' ? 'spacing2Xs' : 'spacingXs'}>
        <ErrorCircleOutlineIcon
          size={density === 'high' ? 'tiny' : 'small'}
          variant="negative"
          aria-hidden="true"
        />
      </Flex>
      <Text
        as="p"
        fontColor="red600"
        fontSize={density === 'high' ? 'fontSizeMHigh' : 'fontSizeM'}
        lineHeight={density === 'high' ? 'lineHeightMHigh' : 'lineHeightM'}
      >
        {children}
      </Text>
    </Flex>
  );
});

ValidationMessage.displayName = 'ValidationMessage';
import React from 'react';
import { useId, type ExpandProps } from '@contentful/f36-core';
import { BaseCheckbox, BaseCheckboxProps } from '../BaseCheckbox';
import { useFormControl } from '../FormControl/FormControlContext';
import { useBaseCheckboxGroup } from '../BaseCheckbox/BaseCheckboxGroupContext';

export type CheckboxProps = Omit<BaseCheckboxProps, 'type' | 'size'>;

const _Checkbox = (
  props: ExpandProps<CheckboxProps>,
  ref: React.Ref<HTMLInputElement>,
) => {
  const {
    testId = 'cf-ui-checkbox',
    id,
    isDisabled,
    isRequired,
    isInvalid,
    children,
    onBlur,
    onChange,
    defaultChecked,
    isChecked,
    value,
    name,
    ...otherProps
  } = props;

  const inputId = useId(id, 'checkbox');

  const groupProps = useBaseCheckboxGroup({
    onBlur,
    onChange,
    value,
    defaultChecked,
    isChecked,
    name,
  });

  // Removes the not needed properties that comes from FormControl context.
  const {
    inputValue,
    setInputValue,
    maxLength,
    setMaxLength,
    isReadOnly,
    ...formProps
  } = useFormControl({
    id: inputId,
    isDisabled,
    isInvalid,
    isRequired,
  });

  return (
    <BaseCheckbox
      {...formProps}
      {...groupProps}
      {...otherProps}
      type="checkbox"
      testId={testId}
      ref={ref}
    >
      {children}
    </BaseCheckbox>
  );
};

export const Checkbox = React.forwardRef(_Checkbox);
import React, { useCallback, useEffect, useRef } from 'react';
import type { PropsWithHTMLElement, ExpandProps } from '@contentful/f36-core';
import type { BaseCheckboxInternalProps } from './types';
import { GhostCheckbox } from './GhostCheckbox';
import getStyles from './BaseCheckbox.styles';
import { Text } from '@contentful/f36-typography';
import { Flex } from '@contentful/f36-core';
import { useDensity } from '@contentful/f36-utils';
import { HelpText } from '../HelpText/HelpText';
import { useFormControl } from '../FormControl/FormControlContext';

export type BaseCheckboxProps = PropsWithHTMLElement<
  BaseCheckboxInternalProps,
  'label',
  'htmlFor'
>;

function _BaseCheckbox(
  props: ExpandProps<BaseCheckboxProps>,
  ref: React.RefObject<HTMLInputElement>,
) {
  const {
    isChecked = undefined,
    onChange,
    onFocus,
    onBlur,
    onKeyDown,
    type = 'checkbox',
    value,
    isDisabled,
    isIndeterminate,
    isInvalid,
    isRequired = false,
    id,
    willBlurOnEsc = true,
    testId = 'cf-ui-base-checkbox',
    className = '',
    defaultChecked = undefined,
    name,
    inputProps = {},
    children,
    'aria-label': ariaLabel,
    size = 'medium',
    helpText,
    ...otherProps
  } = props;
  const density = useDensity();
  const inputRef = useRef<HTMLInputElement>(null);
  const finalRef = ref || inputRef;
  const { id: formFieldId } = useFormControl({});

  useEffect(() => {
    if (finalRef.current) {
      finalRef.current.indeterminate = isIndeterminate;
    }
  }, [isIndeterminate, finalRef]);

  const styles = getStyles({ isDisabled, type, size, density });

  const handleFocus = useCallback(
    (e) => {
      e.persist();
      if (onFocus) {
        onFocus(e);
      }
    },
    [onFocus],
  );

  const handleBlur = useCallback(
    (e) => {
      e.persist();
      if (onBlur) {
        onBlur(e);
      }
    },
    [onBlur],
  );

  const handleKeyDown = useCallback(
    (e) => {
      e.persist();
      if (willBlurOnEsc && e.key === 'Escape') {
        finalRef?.current?.blur();
      }
      if (onKeyDown) {
        onKeyDown(e);
      }
    },
    [willBlurOnEsc, onKeyDown, finalRef],
  );

  const ariaChecked =
    typeof isChecked !== undefined ? isChecked : defaultChecked;

  const helpTextId = id ? `${id}-helptext` : undefined;
  const ariaDescribedBy = isInvalid
    ? `${formFieldId}-validation`
    : helpText
    ? helpTextId
    : undefined;

  return (
    <Flex alignItems="flex-start" flexDirection="column" className={className}>
      <Text
        as="label"
        fontColor="gray900"
        fontWeight="fontWeightMedium"
        fontSize={density === 'high' ? 'fontSizeMHigh' : 'fontSizeM'}
        lineHeight={density === 'high' ? 'lineHeightMHigh' : 'lineHeightM'}
        className={styles.wrapper}
        htmlFor={id}
        testId={testId}
        {...otherProps}
      >
        <input
          {...inputProps}
          aria-label={ariaLabel}
          checked={isChecked}
          defaultChecked={defaultChecked}
          className={styles.input}
          type={type === 'switch' ? 'checkbox' : type}
          onChange={onChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          onKeyDown={handleKeyDown}
          value={value}
          disabled={isDisabled}
          role={type}
          aria-checked={isIndeterminate ? 'mixed' : ariaChecked}
          ref={finalRef}
          required={isRequired}
          aria-required={isRequired ? 'true' : undefined}
