      disabled={isDisabled}
      required={isRequired}
      onChange={handleChange}
      onBlur={onBlur}
      onKeyDown={handleKeyDown}
      onFocus={handleFocus}
      size={size}
    />
  );

  if (icon) {
    return (
      <Box as="div" className={styles.rootComponentWithIcon}>
