    if (typeof setInputValue === 'function') {
      setInputValue(event.target.value);
    }
    onChange?.(event);
  };

  return (
    <BaseInput
      {...otherProps}
      {...formProps}
      defaultValue={defaultValue}
      value={value}
      testId={testId}
      as="textarea"
      ref={ref}
      className={cx(styles.root, className, {
        [styles.disabled]: isDisabled,
        [styles.error]: isInvalid,
